    let n = nums.len();
    let mut max_sum = i64::MIN;

    // Precompute increasing and decreasing sequences
    let mut inc = vec![false; n];
    let mut dec = vec![false; n];
    for i in 1..n {
        if nums[i] > nums[i - 1] {
            inc[i] = true;
        }
        if nums[i] < nums[i - 1] {
            dec[i] = true;
        }
    }

    // Check all possible triplets (l, p, q, r)
    for l in 0..n {
        for p in (l + 1)..n {
            if !inc[p] {
